// Leads.js
import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Leads() {
    const [leads, setLeads] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");
    const [showDecrypted, setShowDecrypted] = useState(false);
    const [role, setRole] = useState(localStorage.getItem("role") || "");
    const navigate = useNavigate();

    const toggleDecrypt = () => setShowDecrypted(v => !v);

    useEffect(() => {
        const fetchLeads = async () => {
            const token = localStorage.getItem("token");
            try {
                const res = await axios.get("http://localhost:8000/leads", {
                    headers: { Authorization: `Bearer ${token}` },
                });
                setLeads(res.data || []);

                // if you want to ensure role comes from server, you can also set it from res.data (if returned)
                // setRole(res.data.role || role);
            } catch (err) {
                console.error("Error fetching leads:", err);
                if (err.response && err.response.status === 401) {
                    setError("Session expired. Please log in again.");
                    localStorage.removeItem("token");
                    localStorage.removeItem("role");
                    navigate("/"); // Redirect to login
                } else {
                    setError("Failed to load leads. Please try again later.");
                }
            } finally {
                setLoading(false);
            }
        };
        fetchLeads();
    }, [navigate]);

    if (loading) return <p className="text-center mt-4">Loading leads...</p>;
    if (error) return <p className="text-danger text-center mt-4">{error}</p>;

    // check if any lead contains raw fields (means server allowed decrypted values for some fields)
    const anyRaw = leads.some(l =>
        l.name_raw || l.username_raw || l.email_raw || l.phone_raw || l.link_url_raw || l.company_name_raw
    );

    return (
        <div className="container mt-4">
            <div className="d-flex justify-content-between align-items-center mb-3">
                <h2 className="mb-0">Leads</h2>

                <div>
                    <button
                        className="btn btn-primary"
                        onClick={toggleDecrypt}
                        disabled={role !== "superadmin"} // only superadmin can toggle
                    >
                        {showDecrypted ? "Show Encrypted" : "Show Decrypted"}
                    </button>

                </div>
            </div>

            {leads.length > 0 ? (
                <table className="table table-striped table-bordered">
                    <thead className="table-dark">
                        <tr>
                            <th>Name</th>
                            <th>Username</th>
                            <th>Email</th>
                            <th>Phone</th>
                            <th>Company URL</th>
                            <th>Company Name</th>
                        </tr>
                    </thead>
                    <tbody>
                        {leads.map((lead, idx) => {
                            // Helper to choose display value or raw if requested AND available
                            const cellValue = (field) => {
                                // field e.g. "name", "email"
                                const rawKey = `${field}_raw`;
                                if (showDecrypted && lead[rawKey] !== undefined) {
                                    // if server provided raw, show it (this respects server's policy)
                                    return lead[rawKey];
                                }
                                // otherwise show server-provided display value
                                return lead[field] ?? "";
                            };

                            return (
                                <tr key={idx}>
                                    <td>{cellValue("name")}</td>
                                    <td>{cellValue("username")}</td>
                                    <td>{cellValue("email")}</td>
                                    <td>{cellValue("phone")}</td>
                                    <td>{cellValue("link_url")}</td>
                                    <td>{cellValue("company_name")}</td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            ) : (
                <p className="text-muted">No leads found.</p>
            )}
        </div>
    );
}

export default Leads;
